      INJURY_DETAILS: lead.injuryDetails,
      INSURANCE_PROVIDER: lead.insuranceProvider,
      INSURANCE_POLICY: lead.insurancePolicyNumber,
      DATE_TODAY: new Date().toISOString().split('T')[0],
      FIRM_NAME: $env.FIRM_NAME || 'Your Firm LLP',
      FIRM_ADDRESS: $env.FIRM_ADDRESS || '',
      ATTORNEY_NAME: $env.ATTORNEY_NAME || 'Senior Partner',
      CASE_ID: lead.caseId,
    }
  }
}];

