parameters.jsCode:
// Convert requiredDocuments array into one item per document so SplitInBatches can iterate
const upstream = $('Merge Classification').first().json;
const folderInfo = $('Create Client Case Folder').first().json;
const branchData = $input.first().json;

const docs = (upstream.requiredDocuments || []).map((docKey) => ({
  documentKey: docKey,
  documentName: docKey.split('_').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' '),
  caseId: upstream.caseId,
  fullName: upstream.fullName,
  lastName: upstream.lastName,
  email: upstream.email,
  category: upstream.category,
  caseType: upstream.caseType,
  placeholders: upstream.placeholders,
  templateFolderId: branchData.templateFolderId,
  caseFolderId: folderInfo.id,
}));

return docs.map(d => ({ json: d }));

