parameters.jsCode:
// Runs after the SplitInBatches done branch fires; collect all generated document records
const all = $('Record Document Info').all();
const upstream = $('Merge Classification').first().json;
const caseFolder = $('Create Client Case Folder').first().json;

const documents = all.map(item => item.json);

return [{
  json: {
    ...upstream,
    caseFolderId: caseFolder.id,
    caseFolderUrl: caseFolder.webViewLink || `https://drive.google.com/drive/folders/${caseFolder.id}`,
    documents,
    documentCount: documents.length,
    documentList: documents.map(d => `• ${d.documentName}`).join('\n'),
  }
}];

