// Expand documents array back into items for the DocuSign loop
const data = $('Aggregate Documents').first().json;
return data.documents.map(d => ({
  json: {
    ...d,
    caseId: data.caseId,
    fullName: data.fullName,
    email: data.email,
    caseType: data.caseType,
    priority: data.priority,
    placeholders: data.placeholders,
    caseFolderId: data.caseFolderId,
    caseFolderUrl: data.caseFolderUrl,
    documentCount: data.documentCount,
  }
}));

const item = $input.item;
const binary = item.binary?.data;
if (!binary) {
  throw new Error('No PDF binary in input');
}
return [{
  json: {
    ...item.json,
    documentBase64: binary.data,  // already base64-encoded by n8n
  }
}];

